import React, { useEffect, useState } from 'react';
import './Hero.css';
import SolutionStep from '../SolutionStep';

function Hero() {
	const [goUp, setGoUp] = useState(false);

	useEffect(() => {
		const onPageScroll = () => {
			if (window.scrollY > 600) {
				setGoUp(true);
			} else {
				setGoUp(false);
			}
		};
		window.addEventListener('scroll', onPageScroll);

		return () => {
			window.removeEventListener('scroll', onPageScroll);
		};
	}, []);

	return (
		<div className="flowhero-section" id="flowherohero">
			<div className="about-image-content">
				<div id="container">
						<div id="circle"></div>
						<div id="small-circle"></div>
						<div id="smaller-circle"></div>
						<div id="smallest-circle"></div>
					</div>
			
			</div>
			<div className="about-text-content">
				<SolutionStep
					title={'What is FlowHero?'}
					description="Our in-house developed cloud solution designed to automate your company's various workflows."
				/>
				<SolutionStep
					title={'What can we do?'}
					description="We can automate your complex business processes and functions using our easy to understand interface. Built on the cloud, concentrate on what your business do best and leave us the worry of data gathering and information delivery to your customers."
				/>
				<SolutionStep
					title="What is the difference between workflows and modules?"
					description="Workflows are the steps undertaken to complete a task and give a result. In Flowhero, modules are subsets of workflows. Think of modules as forms that uses workflows as the underlying steps to make it run, provide the inputs, outputs and create the transaction the workflow is meant to do. Multiple modules can be created from one workflow, all with distinguishing document IDs but having the same input and outputs."
				/>
				<SolutionStep
					title="What's the investment to setup Flowhero?"
					description="Flowhero is accessed via a browser. Let the worry of setting it up and maintaining to us. You just need to subscribe for a plan."
				/>
			</div>
		</div>
	);
}

export default Hero;
